insert into exercises (name, primary_muscle_group, secondary_muscle_groups, muscle_groups, category, movement_type, equipment, difficulty_level, is_compound, instructions, common_mistakes, subcategory, coaching_cues, progressions, regressions, tags, contraindications, force_type, plane_of_motion, is_unilateral, sets_default, reps_default, duration_seconds, rest_seconds, is_system) values

('Foam Roller Quadriceps',
 'quads', array['hip_flexors','rectus_femoris'], array['quads','hip_flexors'],
 'mobility', 'stretch', array['foam_roller'], 'beginner', false,
 'Lie face down with the foam roller under the quads, just above the knee. Support with forearms. Roll slowly from just above the knee to just below the hip. Pause for 30-60 seconds on tender spots. Bend the knee to add tension.',
 'Rolling over the knee joint (must stay on the muscle belly — above the knee cap always), rolling too quickly without pausing at tender spots, forgetting to do both legs.',
 'foam_rolling',
 array['Move: roll 1-2cm at a time, not sweeping the entire length in one go','Pause: when you find a tender spot, stop there and breathe — the release happens during the pause, not during the rolling','Knee bend: bending the knee while on a tender spot dramatically increases the intensity — use this when ready for deeper work','For runners: rolling the quads before and after a run reduces DOMS and maintains muscle extensibility'],
 array['Foam Roller Quad with Knee Bend','Single Leg Quad Roll'],
 array['Light Foam Roller Quad','Softer Foam Roller Quad'],
 array['foam_rolling','quads','recovery','runners','DOMS'],
 array['acute_muscle_tears','bruising','acute_knee_injuries'],
 'isometric', 'sagittal', false, 2, null, 90, 30, true),

('Foam Roller Hamstrings',
 'hamstrings', array['IT_band','calves'], array['hamstrings'],
 'mobility', 'stretch', array['foam_roller'], 'beginner', false,
 'Sit with the foam roller under the hamstrings, hands behind for support. Lift one leg off the roller to concentrate the pressure. Roll from just above the knee to the glute-hamstring junction. Pause on tender spots.',
 'Putting both legs on the roller (cuts the pressure in half — single leg provides meaningful pressure), rolling the back of the knee (must stop above the popliteal fossa — the nerves and blood vessels there should not be compressed).',
 'foam_rolling',
 array['Single leg, not double: one leg on the roller, the other crossed over or hanging — doubles the pressure on the working side','Stop above the knee: the popliteal fossa (back of the knee) contains nerves and arteries — never foam roll directly behind the knee','Cross-friction: rotating the foot inward or outward while on a tender spot creates a cross-friction effect — more effective than pure pressure','Upper hamstring attachment (sit bone area): spend extra time here — the proximal hamstring is where proximal hamstring tendinopathy develops'],
 array['Foam Roller Hamstring Cross-Friction','Lacrosse Ball Hamstring'],
 array['Light Hamstring Rolling','Band-Assisted Hamstring Stretch'],
 array['foam_rolling','hamstrings','recovery','sciatic','runners'],
 array['acute_hamstring_tear','bruising_severe'],
 'isometric', 'sagittal', true, 2, null, 90, 30, true),

('Foam Roller Upper Back and Lats',
 'lats', array['teres_major','rhomboids','erectors'], array['lats','rhomboids'],
 'mobility', 'extension', array['foam_roller'], 'beginner', false,
 'Lie on your side with the roller under the armpit area. Roll along the side body and back, from the armpit down to the lower ribs. Roll across the upper back by placing the roller horizontally across the spine. Spend 90 seconds each area.',
 'Rolling the lumbar spine (must stay above the last rib), not getting into the armpit area (the lat attachment is there — this is often the most productive area and the most neglected).',
 'foam_rolling',
 array['Armpit zone: place the roller in the armpit and roll through the outer back — this is where the lat attaches and where knots commonly develop in desk workers','Upper back horizontal: lie across the roller at the shoulder blade level — extend back gently for thoracic extension while rolling','Do not apply pressure to the lumbar spine: foam rolling the lumbar can create localized tension relief but risks nerve compression','The lats are the largest muscle in the back: they influence shoulder mobility, lower back tension, and breathing quality — regular rolling maintains this large muscle'],
 array['Thoracic Extension on Roller','Lat Stretch with Rolling'],
 array['Light Foam Roller Upper Back','Tennis Ball Upper Back'],
 array['foam_rolling','lats','upper_back','recovery','posture'],
 array['acute_rib_injuries','acute_lat_tears','shoulder_injuries'],
 'isometric', 'multi', true, 2, null, 90, 20, true),

('Foam Roller Calves',
 'calves', array['Achilles_tendon','peroneals','soleus'], array['calves'],
 'mobility', 'stretch', array['foam_roller'], 'beginner', false,
 'Sit on the floor, hands behind you for support. Place the foam roller under one calf. Lift the other leg or cross it over for increased pressure. Roll from just above the ankle to just below the knee. Pause on tight spots.',
 'Rolling with both legs (halves the pressure — use single leg for meaningful effect), rolling over the Achilles tendon insertion (must stop above the ankle bone), moving too quickly.',
 'foam_rolling',
 array['Point and flex the foot: as you pause on a tender spot, alternate between pointing (plantarflexion) and flexing (dorsiflexion) — this creates a movement around the pressure point that is more effective than static compression alone','Peroneals: rotate the calf inward to access the outside of the lower leg (peroneals) — often neglected but critical for ankle stability','Full calf + Achilles system: work from the soleus (lower, deeper) to the gastrocnemius (upper, more superficial) — two sessions per week prevents most running-related calf injuries','After a long run: 5 minutes of calf rolling before calf stretching is the optimal sequence — rolling first makes the stretching more effective'],
 array['Lacrosse Ball Calf Deep Tissue','Calf Rolling with Ankle Circles'],
 array['Soft Foam Roller Calves','Seated Calf Massage'],
 array['foam_rolling','calves','Achilles','runners','recovery'],
 array['acute_calf_tear','acute_Achilles_rupture','deep_vein_thrombosis_risk'],
 'isometric', 'sagittal', true, 2, null, 90, 20, true),

('Tennis Ball Foot Rolling',
 'calves', array['plantar_fascia','intrinsic_foot_muscles'], array['calves','plantar_fascia'],
 'mobility', 'stretch', array['tennis_ball','lacrosse_ball'], 'beginner', false,
 'Stand or sit. Place a tennis ball under one foot. Apply comfortable pressure and roll the ball from the heel to the ball of the foot, pausing on tender spots. Spend 2-3 minutes per foot.',
 'Applying too much pressure immediately (should build gradually — a golf ball is harder than a tennis ball — progress slowly), rolling the arch only (must also address the ball of the foot and the heel area, where plantar fasciitis commonly begins).',
 'foam_rolling',
 array['The three zones: heel (plantar fascia origin) → arch (main fascia body) → ball of foot (metatarsal heads) — give each zone equal attention','Seated vs standing: seated allows less pressure (preferred for those with plantar fasciitis), standing allows more weight — match to what is productive','Freezing the tennis ball: a cold tennis ball provides both myofascial release AND cryotherapy — useful for acute plantar fasciitis','Daily habit: 5 minutes of foot rolling while watching morning TV prevents the heel pain of the first morning steps that affects millions of people'],
 array['Lacrosse Ball Foot Deep Tissue','Golf Ball Intrinsic Foot Work'],
 array['Warm Water Foot Massage','Gentle Foot Circles'],
 array['foam_rolling','plantar_fascia','foot_health','runners','daily_routine'],
 array['acute_plantar_fasciitis_very_inflamed','stress_fractures_foot'],
 'isometric', 'sagittal', true, 2, null, 120, 20, true),

('Foam Roller Hip Flexors',
 'hip_flexors', array['psoas','iliacus','rectus_femoris'], array['hip_flexors','psoas'],
 'mobility', 'stretch', array['foam_roller'], 'intermediate', false,
 'Lie face down with the foam roller placed diagonally under the front of the hip, just medial to the hip bone (ASIS). Roll slightly back and forth to find the iliacus and psoas attachment. Hold 60-90 seconds each side.',
 'Placing the roller too lateral (must go medial to the ASIS — too far out is the TFL, not the hip flexor), arching the lower back during the rolling, applying too much body weight immediately.',
 'foam_rolling',
 array['The target: the roller goes just inside (medial to) the bony point at the front of the hip — this is where the iliacus attaches','Breathe through the discomfort: the psoas is innervated by multiple lumbar nerves — emotional and stress responses are common when releasing this muscle','Tense legs = minimal release: relax the working leg completely — let it hang or place it in a comfortable position','The psoas is called the ''muscle of the soul'' in some body-work traditions: it connects the spine to the leg and is the muscle most affected by chronic stress and prolonged sitting'],
 array['Lacrosse Ball Hip Flexor Deep','Active Hip Flexor Release'],
 array['Light Pressure Hip Flexor Release','Standing Hip Flexor Stretch'],
 array['foam_rolling','hip_flexor','psoas','recovery','desk_workers'],
 array['acute_hip_flexor_strain','abdominal_surgery_recent'],
 'isometric', 'sagittal', true, 2, null, 90, 20, true),

('Lacrosse Ball Plantar Fascia',
 'calves', array['plantar_fascia','intrinsic_foot_muscles'], array['calves','plantar_fascia'],
 'mobility', 'stretch', array['lacrosse_ball'], 'beginner', false,
 'Stand near a wall for balance. Place the lacrosse ball under the heel. Apply body weight. Roll forward to the arch, then to the ball of the foot. Pause at any tender spots for 30-60 seconds. Progress to single-leg standing for maximum pressure.',
 'Using too hard a ball before the tissue is ready (start with a tennis ball, progress to lacrosse ball, then golf ball over weeks), rolling only the arch (the heel and ball of the foot are equally important zones).',
 'foam_rolling',
 array['The heel is the most important zone for plantar fasciitis: 80% of plantar fasciitis originates at the calcaneal insertion','Single-leg pressure: once both feet are comfortable, progress to single-leg standing on the ball for therapeutic pressure','Progress slowly: more pressure is not always better — enough pressure to feel productive tension, not sharp or shooting pain','Morning habit: 3 minutes of foot rolling before getting out of bed in the morning dramatically reduces the first-step heel pain of plantar fasciitis'],
 array['Golf Ball Deep Tissue Foot','Sock Toe Stretch Combination'],
 array['Tennis Ball Foot Rolling','Gentle Foot Self-Massage'],
 array['foam_rolling','plantar_fascia','heel_pain','runners','prevention'],
 array['stress_fractures_calcaneus','acute_plantar_fascia_tear'],
 'isometric', 'sagittal', true, 2, null, 120, 20, true),

('Foam Roller Thoracic Spine Segmental',
 'erectors', array['rhomboids','trapezius','intercostals'], array['erectors','rhomboids'],
 'mobility', 'extension', array['foam_roller'], 'beginner', false,
 'Lie with foam roller perpendicular to spine at the upper thoracic. Support the head with interlaced fingers. Extend back gently over the roller for 5-10 seconds. Move the roller one vertebral segment down. Repeat down to T12 (last rib level). Stop there.',
 'Going below the last rib (lumbar foam rolling is not appropriate — the lumbar spine hyperextends dangerously on a foam roller), not moving segmentally (sweeping the roller misses the targeted extension at each level).',
 'foam_rolling',
 array['One segment at a time: move the roller about 2cm at a time and perform the extension at each level','T1-T12 only: 12 thoracic vertebrae get a dedicated extension before the roller is removed — this takes 3-5 minutes when done properly','Head supported throughout: if the head hangs unsupported, the cervical spine strains — hands behind the head at all times','This is the most efficient thoracic mobility tool available: one session of segmental foam roller extension can restore 10-20° of lost thoracic extension'],
 array['Foam Roller with Arm Reach','Peanut (Double Lacrosse Ball) Thoracic'],
 array['Chair Thoracic Extension','Standard Foam Roller Extension'],
 array['foam_rolling','thoracic','posture','recovery','daily_routine'],
 array['vertebral_fractures','osteoporosis_severe','acute_thoracic_injury'],
 'push', 'sagittal', false, 1, null, 300, null, true),

('Foam Roller Peroneals',
 'peroneals', array['calves','IT_band'], array['peroneals','calves'],
 'mobility', 'stretch', array['foam_roller'], 'beginner', false,
 'Sit on the floor with the foam roller under the outer lower leg (peroneals — the muscles on the outside of the shin). Roll from just above the ankle to just below the knee on the lateral surface. Pause on tight spots.',
 'Mistaking this for IT band rolling (peroneals are on the outer lower leg, below the knee — IT band is the outer thigh, above the knee), applying too much direct pressure on the fibular head (the bony prominence just below the outer knee).',
 'foam_rolling',
 array['The outer lower leg: below the knee, on the outside — this is distinctly different from calf or IT band work','Avoid the fibular head: move the roller around the bony protrusion at the outer knee — do not apply direct pressure here','Peroneal tightness is common in trail runners and sports with lateral cutting: regular rolling maintains the ankle eversion strength and flexibility','Combine with ankle circles: after rolling, perform 20 ankle circles each direction — the combined effect is greater than either alone'],
 array['Lacrosse Ball Peroneal','Active Peroneal Stretching'],
 array['Light Foam Roller Lower Leg','Ankle Circles'],
 array['foam_rolling','peroneals','ankle_stability','runners','injury_prevention'],
 array['acute_ankle_sprains','peroneal_tendon_tears_acute'],
 'isometric', 'frontal', true, 2, null, 60, 20, true),

('Foam Roller Adductors',
 'inner_thighs', array['groin','hip_adductors'], array['inner_thighs','groin'],
 'mobility', 'stretch', array['foam_roller'], 'intermediate', false,
 'Lie face down, one leg turned out with the inner thigh on the foam roller. Roll from just above the knee to the groin, pausing on tender spots. Flex and extend the knee while on a tender spot to create cross-friction.',
 'Rolling directly over the groin attachment at the very top of the inner thigh (too sensitive — stay on the muscle belly), applying too much pressure immediately (adductors are more sensitive than quads or hamstrings).',
 'foam_rolling',
 array['Adductors are often severely neglected in rolling protocols: most people roll quads, hamstrings, and IT bands, rarely the inner thigh','The roller goes inside the thigh: not on top, not on the side — on the literal inner surface of the thigh','Knee flexion/extension while on a spot: bending and straightening the knee while the roller is on a tender spot creates a dynamic release that is more effective than static pressure','Used in sports with lateral movements (soccer, hockey, martial arts, dance): tight adductors directly limit ground clearance and lateral agility'],
 array['Lacrosse Ball Inner Thigh','Active Adductor Strengthening After Rolling'],
 array['Light Foam Roller Inner Thigh','Supine Adductor Stretch'],
 array['foam_rolling','adductors','inner_thighs','sports_specific','recovery'],
 array['acute_groin_injury','groin_tears','bruising_severe'],
 'isometric', 'frontal', true, 2, null, 90, 20, true),

('Foam Roller Tibialis Anterior',
 'tibialis_anterior', array['toe_extensors'], array['tibialis_anterior'],
 'mobility', 'stretch', array['foam_roller','lacrosse_ball'], 'beginner', false,
 'Sit with the foam roller under the front of the shin (anterior surface — the shin muscle, not the shin bone). Roll from just above the ankle to just below the knee. Use a lacrosse ball for more targeted pressure.',
 'Rolling on the tibia bone (must be on the muscle tissue beside the bone — rolling directly on bone is painful and counterproductive), not checking both shins (asymmetric tightness is common and often missed).',
 'foam_rolling',
 array['Lateral to the bone: the tibialis anterior sits just to the outside of the shin bone — place the roller there, not on the bone itself','The muscle of dorsiflexion: tibialis anterior is the primary ankle dorsiflexor — rolling it maintains ankle mobility and prevents shin splints','Lacrosse ball for targeted work: once the foam roller has loosened the tissue, a lacrosse ball allows precise work at specific tender points','Shin splints prevention: rolling the tibialis anterior AND performing tibialis raises (pointing the toes up against resistance) is the most effective shin splints prevention protocol'],
 array['Lacrosse Ball Tibialis','Active Tibialis Strengthening'],
